window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2003>1>a","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"a","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Specimen A in group II is a bony fish/Tilapia and specimen B in group I is a tadpole    Name the adult stage of specimen B","images":[],"marking_scheme":"The name of the adult stage of specimen B is toad.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>1>b>i","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"List four external features common to specimens A and B","images":[],"marking_scheme":"The external features common to specimens A (Tilapia) and B (Tadpole).  -They both have tail.   -They both have caudal fin.   -They both have nostrils.   -They both have mouth.   -They both have eye   -They both have operculum.   -They both have streamlined body.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>1>b>ii","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"In a tabular form, list four observable differences between specimens A and B","images":[],"marking_scheme":"Specimen A (Tilapia)Specimen B (Tadpole)Presence of short tailPresence of long tailPresence of limbsAbsence of limbsPresence of scalesAbsence of scalesPresence of lateral linesAbsence of lateral linesMany fins presentHas only one fin","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>1>b>iii","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"iii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Make a labelled drawing of 8cm to 10cm long of specimen A to show its external features.","images":["data:image/jpeg;base64,"],"marking_scheme":"Tilapia/Bony fish","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>1>b>iv","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"iv","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State, how four of its external features adapt the specimen A to its environment","images":[],"marking_scheme":"It has streamlined body for rapid movement with least resistant in water it has caudal fin for steering it has muscular tail for moving forward It has median and dorsal fins for stability or balancing in water it has overlapping scales for protection and least resistance when moving in water It has lateral lines for detecting vibrations and movement in water it possesses gill cover which protects the gills and aids in respiration It possesses mouth for feeding and respiration It has dark grey dorsal and silvery ventral surface for camouflage against predator","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>1>b>v","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"v","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Name two classes of food that specimen A provides in human nutrition","images":[],"marking_scheme":"The classes of food provided by specimen A for human consumption  -It provides protein,   -It provides fat and oil.   -It provides vitamins","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>2>a","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"a","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Specimen C in group I is a piece of sprouting cassava stem, specimen D in group III is a sprouting onion bulb and specimen E in group II is a spouting Irish potato Carefully, examine specimens C,D and E and comment on their features of biological interest","images":[],"marking_scheme":"The features of Biological interest of specimens C, D and E.   -Specimen C (Sprouting cassava Stem),  -Specimen D (Sprouting Onion bulb),   -Specimen E (Sprouting Irish Potato)   They are all organs of vegetative propagation. They all show sprouting buds  The specimen C is a woody surface stem with the buds and nodes which obtains nutrient from stored food in the xylem parenchyma  Specimen D obtains nutrient from the food stored in fleshy leaves  Specimen E is an underground stem that depends on food stored in the stem","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2003>2>b>i","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Specimen F in group III are wet spirogyra strands, specimen G in group III is an earthworm, specimen H in group Il is a bird, specimen J in group I is periwinkle and specimen K in group II is a crab. Carefully, examine specimens F, G, H, J and K    Name their respiratory surfaces in order of evolutionary trend","images":[],"marking_scheme":"The respiratory surfaces of F.G. H. J and K in order of evolutionary trend    F (Spirogyra) has cell membrane, body surface or body covering J (Periwinkle) has gills, K (Crab) has gills, G (Earth- worm) has skin or moist body surface H (Bird) has lungs. Cell membrane \u2192 Gills \u2192  Skin \u2192  Lungs","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2003>2>b>ii","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Which of the respiratory surfaces is most primitive? Give reasons","images":[],"marking_scheme":"The most primitive respiratory surface is the membrane The reason is that, it is very simple and very thin","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>2>b>iii","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"iii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Using specimens F, G, H, J and K, construct a pyramid of energy, using box representation. Fill in the different organisms at the various trophic levels/food chain","images":["data:image/jpeg;base64,"],"marking_scheme":"Construction of Pyramid of energy using specimens F.G.H.J and K","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2003>2>b>iv","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"iv","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"Name the organisms with the greatest and least amounts of the captured energy","images":[],"marking_scheme":"The organism with the greatest amount of captured energy is the spirogyra.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>2>c>i","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"i","group":"","topic":"APPLICATION OF VARIATIONS :","question":"Place the thumb of your right hand, face-down on an ink pad, exerting a little bit of pressure on it. Press the same treated thumb on your answer script, still exerting a little pressure Observe the result on your answer script Wash your thumb immediately after the experiment    What name is given to the observation on your answer script? Mention one use of it to mankind. Give reasons","images":[],"marking_scheme":"The experiment with the right-thumb  It is called fingerprint or thumb print Fingerprint is used by mankind for crime detection, identification of individual or appending signatures The reason for the use of fingerprint to mankind is that the ridges of the fingerprints differ from individual to individual and crime committed by individual persons are easily detected,","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2003>2>c>ii","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"ii","group":"","topic":"APPLICATION OF VARIATIONS :","question":"What area in the study of Biology is your observation associated with?","images":[],"marking_scheme":"The area of Biology fingerprint is associated with is variation or morphological variation","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>3>a>i","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"i","group":"","topic":"SOIL","question":"Specimen N in group Il is a soil sample Put some quantity of soil in a 250cm3 measuring cylinder/glass jar (about half- filled).  Add sufficient amount of water to cover the soil sample    What do you observe as you add the water?","images":[],"marking_scheme":"The observation made as water was poured into the soil sample.  There were bubbles of air that was given off","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>3>a>ii","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"ii","group":"","topic":"SOIL","question":"Of what use is your observation in 4(a)(i) above to the soil?","images":[],"marking_scheme":"The use of air bubbles in the soil   -It provides oxygen, nitrogen and carbon dioxide and also aerates the soil   -It provides aerobic respiration for soil organisms,   -It makes the soil porous, It contributes to soil fertility","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>3>a>iii","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"iii","group":"","topic":"SOIL","question":"Cover the measuring cylinder/glass jar with your palm and shake thoroughly Leave to stand on a smooth table for about 30 minutes. Record your observation(s) in your answer script","images":[],"marking_scheme":"The observation made of soil sample with water in the cylinder    The soil sample settles in different layers The coarse particles settle at the bottom, followed by silt layer, clay layer suspension of fine sandy layer and floating dead organic matter (humus) on top of the water","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>3>a>iv","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"iv","group":"","topic":"SOIL","question":"Suggest a suitable title for the experiment","images":[],"marking_scheme":"The suitable title for the experiment The experiment to show that soil contains different sizes of particles or separation of soil particles from humus by sedimentation.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>3>a>v","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"v","group":"","topic":"SOIL","question":"Make a labelled drawing of 8cm to 10cm long of the contents in the cylinder/jar","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>3>a>vi","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"vi","group":"","topic":"SOIL","question":"State the role(s) of the floating substance on the surface of the water in question 4(a)(iii).","images":[],"marking_scheme":"The role of floating substance (humus) in the soil:  -It improves soil fertility.   -It provides plant nutrients especially nitrogen, phosphorus and sulphur,   - It releases organic acid during decomposition, which helps to dissolve minerals in rocks.  - It increases cation exchange in the soil.  The decomposition of humus releases carbon dioxide and ammonia to the atmosphere.  - It reduces soil erosion by binding soil particles together  - It makes it possible for burrowing animals e g. earthworm ants, rodents to inhabit the soil for better air and water infiltration  - It reduces evaporation by formation of surface mulch.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2003>3>b","subject":"Biology Practical","year":"2003","type":"Practical","sub_label":"b","group":"","topic":"SOIL","question":"Mention two importance of soil to plants","images":[],"marking_scheme":"The importance of soil to plants   -It provides anchorage for the plants.   -It improves soil fertility for better plant growth It provides soil nutrients and raw materials for photosynthesis e.g. water  - It provides dissolved inorganic minerals for healthy growth of plants","marks":"1","difficulty":"2"}];